import React, { useState, useEffect, useContext, useCallback } from 'react';
import {
  Box, Container, Typography, Card, CardContent, Grid,
  Table, TableBody, TableCell, TableContainer, TableHead, TableRow,
  Paper, Chip, Avatar, IconButton, Tooltip, TextField, InputAdornment,
  Select, MenuItem, FormControl, InputLabel, Button, Dialog, DialogTitle,
  DialogContent, DialogActions, List, ListItem, ListItemText, Divider,
  Alert, CircularProgress, Badge, AppBar, Toolbar
} from '@mui/material';
import {
  Search, FilterList, Person, Email, TrendingUp, TrendingDown,
  Close, Visibility, AdminPanelSettings, CheckCircle, Cancel, 
  AccountCircle, Settings, Security, ShowChart, LocalAtmRounded,
  CloseOutlined, Logout, Dashboard, PeopleAlt, PersonAdd, 
  VerifiedUser, Block, RefreshRounded, AttachMoney, BarChart
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { AuthContext } from '../../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import OpenOrdersCard from './OpenOrdersCard';

const AdminDashboard = () => {
  console.log('AdminDashboard: Componente carregando...');
  
  const { logout } = useContext(AuthContext);
  const navigate = useNavigate();
  
  const [users, setUsers] = useState([]);
  const [filteredUsers, setFilteredUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isAutoUpdating, setIsAutoUpdating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [stats, setStats] = useState({
    total_users: 0,
    active_users: 0,
    inactive_users: 0,
    admin_users: 0,
    total_under_management_usd: 0,
    open_positions: {
      positive_count: 0,
      negative_count: 0,
      total_roe_percentage: 0
    }
  });

  useEffect(() => {
    console.log('AdminDashboard: useEffect inicial - carregando dados...');
    fetchAdminData();
  }, []);

  useEffect(() => {
    console.log('AdminDashboard: Filtrando usuários...');
    filterUsers();
  }, [users, searchTerm, statusFilter]);

  // Auto-atualização a cada 30 segundos
  useEffect(() => {
    const interval = setInterval(async () => {
      console.log('🔄 [AUTO-UPDATE] Atualizando dados admin silenciosamente...');
      setIsAutoUpdating(true);
      await fetchAdminData(false); // Carregamento silencioso
      setTimeout(() => setIsAutoUpdating(false), 1000);
    }, 30000);

    return () => clearInterval(interval);
  }, []);

  const fetchAdminData = useCallback(async (showLoading = true) => {
    if (showLoading) setLoading(true);
    try {
      const [usersResponse, statsResponse] = await Promise.all([
        fetch('/api/admin/users', { credentials: 'include' }),
        fetch('/api/admin/dashboard/stats', { credentials: 'include' })
      ]);

      if (!usersResponse.ok || !statsResponse.ok) {
        throw new Error('Falha ao carregar dados do administrador.');
      }

      const usersData = await usersResponse.json();
      const statsData = await statsResponse.json();

      setUsers(usersData.users || []);
      setStats({
        total_users: usersData.summary?.total_users || 0,
        active_users: usersData.summary?.active_users || 0,
        inactive_users: usersData.summary?.inactive_users || 0,
        total_under_management_usd: statsData.total_under_management_usd || 0,
        open_positions: statsData.open_positions || {
          positive_count: 0,
          negative_count: 0,
          total_roe_percentage: 0
        }
      });

    } catch (error) {
      console.error("Erro ao carregar dados do admin:", error);
      toast.error(error.message || 'Erro ao carregar dados.');
    } finally {
      if (showLoading) setLoading(false);
    }
  }, []);

  const filterUsers = () => {
    let filtered = users;

    // Filtro de busca
    if (searchTerm) {
      filtered = filtered.filter(user =>
        user.full_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.email.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    // Filtro de status
    if (statusFilter !== 'all') {
      filtered = filtered.filter(user => {
        if (statusFilter === 'active') return user.is_active;
        if (statusFilter === 'inactive') return !user.is_active;
        if (statusFilter === 'admin') return user.is_admin;
        return true;
      });
    }

    setFilteredUsers(filtered);
  };

  const handleUserClick = (user) => {
    console.log(`AdminDashboard: Navegando para o dashboard do usuário: ${user.full_name}`);
    navigate(`/admin/user/${user.id}`);
  };

  const handleToggleNautilusStatus = async (userId) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}/toggle-nautilus-status`, {
        method: 'POST',
        credentials: 'include'
      });
      const data = await response.json();
      if (response.ok) {
        toast.success(data.message);
        fetchAdminData(false);
      } else {
        toast.error(data.message);
      }
    } catch (error) {
      toast.error('Erro ao alterar status Nautilus.');
    }
  };

  const handleToggleUserStatus = async (userId) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}/toggle-status`, {
        method: 'POST',
        credentials: 'include'
      });
      if (response.ok) {
        toast.success('Status do usuário atualizado.');
        fetchAdminData(false);
      } else {
        toast.error('Erro ao atualizar status do usuário.');
      }
    } catch (error) {
      toast.error('Erro ao atualizar status.');
    }
  };

  // Função para fazer logout
  const handleLogout = async () => {
    console.log('AdminDashboard: Logout');
    await logout();
    navigate('/login');
  };

  const getStatusColor = (isActive) => {
    return isActive ? 'success' : 'error';
  };

  const getStatusText = (isActive) => {
    return isActive ? 'Ativo' : 'Inativo';
  };

  const getPnlColor = (pnl) => {
    if (pnl > 0) return 'success.main';
    if (pnl < 0) return 'error.main';
    return 'text.secondary';
  };

  const formatUsd = (value, fractionDigits = 2) => {
    const num = Number(value);
    return isNaN(num) ? '$0.00' : num.toLocaleString('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: fractionDigits,
      maximumFractionDigits: fractionDigits
    });
  };
  
  const formatPercentage = (value) => {
    return `${(value || 0).toFixed(4)}%`;
  }

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1, bgcolor: '#1a1a1a' }}>
        <Toolbar>
          <AdminPanelSettings sx={{ mr: 2, fontSize: 30, color: '#f0b90b' }} />
          <Typography variant="h6" noWrap component="div" sx={{ flexGrow: 1, color: '#f0b90b' }}>
            Admin Dashboard
          </Typography>
          {isAutoUpdating && <CircularProgress size={24} color="inherit" />}
          <Tooltip title="Atualizar Dados">
            <IconButton onClick={() => fetchAdminData(true)} color="inherit">
              <RefreshRounded />
            </IconButton>
          </Tooltip>
          <Tooltip title="Sair">
            <IconButton onClick={handleLogout} color="inherit">
              <Logout />
            </IconButton>
          </Tooltip>
        </Toolbar>
      </AppBar>
      
      <Box component="main" sx={{ flexGrow: 1, p: 3, bgcolor: '#121212', minHeight: '100vh', mt: '64px' }}>
        <Container maxWidth="xl" sx={{ mt: 4, mb: 4 }}>
          {loading && <CircularProgress sx={{ display: 'block', margin: 'auto' }} />}
          
          <Grid container spacing={3}>
            {/* Novo Card de Ordens Abertas */}
            <Grid item xs={12} sm={6} md={3}>
              <OpenOrdersCard stats={stats} />
            </Grid>
            
            {/* Card de Valor Sob Gestão */}
            <Grid item xs={12} sm={6} md={3}>
              <Card sx={{ bgcolor: 'primary.main', color: 'white', height: '100%' }}>
                <CardContent>
                  <Typography variant="h6" gutterBottom>Valor Sob Gestão (USD)</Typography>
                  <Box sx={{ display: 'flex', alignItems: 'center', mt: 2 }}>
                    <AttachMoney sx={{ fontSize: 40, mr: 2 }} />
                    <Typography variant="h4">
                      {formatUsd(stats.total_under_management_usd)}
                    </Typography>
                  </Box>
                </CardContent>
              </Card>
            </Grid>

            {/* Cards de contagem de usuários agrupados */}
            <Grid item xs={12} md={6}>
              <Grid container spacing={2}>
                <Grid item xs={12} sm={4}>
                  <Card sx={{ bgcolor: '#424242', color: 'white', height: '100%', textAlign: 'center' }}>
                    <CardContent>
                      <Typography>Total</Typography>
                      <Typography variant="h4">{stats.total_users}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} sm={4}>
                  <Card sx={{ bgcolor: 'success.dark', color: 'white', height: '100%', textAlign: 'center' }}>
                    <CardContent>
                      <Typography>Ativos</Typography>
                      <Typography variant="h4">{stats.active_users}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} sm={4}>
                  <Card sx={{ bgcolor: 'error.dark', color: 'white', height: '100%', textAlign: 'center' }}>
                    <CardContent>
                      <Typography>Inativos</Typography>
                      <Typography variant="h4">{stats.inactive_users}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
              </Grid>
            </Grid>
          </Grid>

          {/* Tabela de Usuários */}
          <Card sx={{ mt: 4, borderRadius: 3, boxShadow: '0 8px 32px 0 rgba(31, 38, 135, 0.37)' }}>
            <CardContent>
              {/* Cabeçalho da Tabela e Filtros */}
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2, flexWrap: 'wrap', gap: 2 }}>
                <Typography variant="h6">Usuários</Typography>
                <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
                  <TextField
                    label="Buscar Usuário"
                    variant="outlined"
                    size="small"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <Search />
                        </InputAdornment>
                      ),
                    }}
                  />
                  <FormControl variant="outlined" size="small" sx={{ minWidth: 120 }}>
                    <InputLabel>Status</InputLabel>
                    <Select
                      value={statusFilter}
                      onChange={(e) => setStatusFilter(e.target.value)}
                      label="Status"
                    >
                      <MenuItem value="all">Todos</MenuItem>
                      <MenuItem value="active">Ativos</MenuItem>
                      <MenuItem value="inactive">Inativos</MenuItem>
                      <MenuItem value="admin">Admins</MenuItem>
                    </Select>
                  </FormControl>
                  <Tooltip title="Atualizar Dados">
                    <IconButton onClick={() => fetchAdminData()} color="primary" disabled={loading}>
                      {loading ? <CircularProgress size={24} /> : <RefreshRounded />}
                    </IconButton>
                  </Tooltip>
                </Box>
              </Box>

              {/* Tabela */}
              <TableContainer component={Paper} sx={{ borderRadius: 2 }}>
                <Table stickyHeader aria-label="users table">
                  <TableHead>
                    <TableRow>
                      <TableCell sx={{ fontWeight: 'bold' }}>Usuário</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Status</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Último Login</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Total de Trades</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Total PNL (USD)</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Total sob Gestão (USD)</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Status Nautilus</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Ações</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {loading ? (
                      <TableRow>
                        <TableCell colSpan={8} align="center">
                          <CircularProgress />
                        </TableCell>
                      </TableRow>
                    ) : filteredUsers.length > 0 ? (
                      filteredUsers.map((user) => (
                        <TableRow key={user.id} hover sx={{ '&:last-child td, &:last-child th': { border: 0 } }}>
                          <TableCell>
                            <Box sx={{ display: 'flex', alignItems: 'center' }}>
                              <Avatar sx={{ bgcolor: getStatusColor(user.is_active), width: 32, height: 32, mr: 1.5 }}>
                                <Person sx={{ fontSize: '1rem' }} />
                              </Avatar>
                              <Box>
                                <Typography variant="body2" fontWeight="bold">{user.full_name}</Typography>
                                <Typography variant="caption" color="text.secondary">{user.email}</Typography>
                              </Box>
                            </Box>
                          </TableCell>
                          <TableCell align="center">
                            <Tooltip title={user.is_active ? 'Usuário Ativo' : 'Usuário Inativo'}>
                              <Chip 
                                label={getStatusText(user.is_active)}
                                color={getStatusColor(user.is_active)}
                                size="small"
                              />
                            </Tooltip>
                          </TableCell>
                          <TableCell align="center">
                            <Typography variant="body2">{formatDate(user.last_login)}</Typography>
                          </TableCell>
                          <TableCell align="center">
                            <Typography variant="body2">{user.total_trades || 0}</Typography>
                          </TableCell>
                          <TableCell align="center" sx={{ color: getPnlColor(user.total_pnl), fontWeight: 'medium' }}>
                            <Typography variant="body2" sx={{color: getPnlColor(user.total_pnl)}}>
                              {formatUsd(user.total_pnl, 2)}
                            </Typography>
                          </TableCell>
                          <TableCell align="center">
                            <Typography variant="body2">
                              {formatUsd(user.balance_usd, 2)}
                            </Typography>
                          </TableCell>
                          <TableCell align="center">
                            <Chip 
                              icon={user.nautilus_active ? <CheckCircle /> : <Cancel />}
                              label={user.nautilus_active ? 'Ativo' : 'Inativo'}
                              color={user.nautilus_active ? 'success' : 'error'}
                              variant="outlined"
                              size="small"
                              onClick={(e) => {
                                e.stopPropagation();
                                handleToggleNautilusStatus(user.id);
                              }}
                              sx={{ cursor: 'pointer' }}
                            />
                          </TableCell>
                          <TableCell align="center">
                            <Tooltip title="Ver Dashboard do Usuário" arrow>
                              <IconButton color="primary" onClick={() => handleUserClick(user)}>
                                <Dashboard />
                              </IconButton>
                            </Tooltip>
                            {!user.is_admin && (
                              <Tooltip title={user.is_active ? 'Desativar Usuário' : 'Ativar Usuário'}>
                                <IconButton onClick={(e) => { e.stopPropagation(); handleToggleUserStatus(user.id); }}>
                                  {user.is_active ? <Cancel sx={{ color: 'error.main' }} /> : <CheckCircle sx={{ color: 'success.main' }} />}
                                </IconButton>
                              </Tooltip>
                            )}
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell align="center" colSpan={8}>
                          <Typography variant="body1" sx={{ p: 2 }}>Nenhum usuário encontrado</Typography>
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </TableContainer>
            </CardContent>
          </Card>
        </Container>
      </Box>
    </Box>
  );
};

export default AdminDashboard;
